mapper.select:
SELECT m.*, (SELECT COUNT(*) FROM warning w WHERE w.member_id = m.member_id AND w.warning_status = '유효') AS warningCount FROM member m WHERE m.member_delete_status = '정상'
AND (m.member_loginid LIKE CONCAT('%', #{keyword}, '%') OR m.member_name LIKE CONCAT('%', #{keyword}, '%') OR m.member_email LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY m.member_created_at DESC LIMIT #{offset}, #{size}

